sql:
SELECT year, COUNT(super_bowl_id) AS number_of_events
FROM super_bowl_events
GROUP BY year;

SELECT COUNT(broadcast_id) AS broadcast_count
FROM super_bowl_broadcasts
WHERE network_id = 1;

SELECT winner, COUNT(*) AS win_count
FROM super_bowl_events
GROUP BY winner;

SELECT winner, loser
FROM super_bowl_events
ORDER BY attendance DESC;

SELECT year, winner
FROM super_bowl_events
ORDER BY year DESC;

SELECT year, location, attendance, winner
FROM super_bowl_events
ORDER BY attendance DESC;

SELECT year
FROM super_bowl_events
ORDER BY year DESC;

SELECT avg_us_viewers AS average_us_viewers
FROM super_bowl_broadcasts
WHERE avg_us_viewers = (SELECT MAX(avg_us_viewers) FROM super_bowl_broadcasts);

external_knowledge:
- 'Top-rated' refers to the highest positive rating in each demographic group;
- 'Demographic groups' are categorized based on age range and gender;
- 'Neutral or negative feedback' is represented by ratings that are zero or less in the database.

- "path of gold and viewers" refers to the financial success and viewership metrics;
- "network’s beacon" refers to the network name;
- "type of channel" refers to the network type;
- "how many millions it draws" refers to the average and total viewership in millions;
- "average rating of the viewing crowd" refers to the average rating and share of the viewers;
- "financial windfall from ads" refers to the total ad revenue;
- "gold per dollar sown" refers to ad revenue per million dollars of production cost;
- "potential audience sway" refers to the estimated viewer impact;
- "grand broadcast network" refers to the broadcast network managing the Super Bowl broadcasts.

sql:
SELECT SUM(sb.total_revenue) AS total_revenue
FROM super_bowl_broadcasts sb
INNER JOIN super_bowl_events se ON sb.super_bowl_id = se.super_bowl_id;
